import type { ComponentProps } from 'react';
import { PreviewCard as PreviewCardPrimitive } from '@base-ui/react/preview-card';
import { PopupArrowIcon } from '@/lib/moduix/icons/ui';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './PreviewCard.module.css';

type PreviewCardPositionerProps = Pick<
  PreviewCardPrimitive.Positioner.Props,
  | 'side'
  | 'sideOffset'
  | 'align'
  | 'alignOffset'
  | 'arrowPadding'
  | 'collisionAvoidance'
  | 'collisionBoundary'
  | 'collisionPadding'
>;

type PreviewCardContentProps = PreviewCardPrimitive.Popup.Props &
  PreviewCardPositionerProps & {
    showArrow?: boolean;
  };

const DEFAULT_SIDE_OFFSET = 8;

const PreviewCard = PreviewCardPrimitive.Root;
const createPreviewCardHandle = PreviewCardPrimitive.createHandle;

function PreviewCardTrigger<Payload = unknown>({
  className,
  render,
  ...props
}: PreviewCardPrimitive.Trigger.Props<Payload>) {
  const triggerClassName = render ? className : mergeClassName(className, styles.trigger);

  return (
    <PreviewCardPrimitive.Trigger
      data-slot="preview-card-trigger"
      render={render}
      className={triggerClassName}
      {...props}
    />
  );
}

function PreviewCardPortal(props: PreviewCardPrimitive.Portal.Props) {
  return <PreviewCardPrimitive.Portal data-slot="preview-card-portal" {...props} />;
}

function PreviewCardBackdrop({ className, ...props }: PreviewCardPrimitive.Backdrop.Props) {
  return (
    <PreviewCardPrimitive.Backdrop
      data-slot="preview-card-backdrop"
      className={mergeClassName(className, styles.backdrop)}
      {...props}
    />
  );
}

function PreviewCardPositioner({ className, ...props }: PreviewCardPrimitive.Positioner.Props) {
  return (
    <PreviewCardPrimitive.Positioner
      data-slot="preview-card-positioner"
      className={mergeClassName(className, styles.positioner)}
      {...props}
    />
  );
}

function PreviewCardPopup({ className, ...props }: PreviewCardPrimitive.Popup.Props) {
  return (
    <PreviewCardPrimitive.Popup
      data-slot="preview-card-popup"
      className={mergeClassName(className, styles.popup)}
      {...props}
    />
  );
}

function PreviewCardArrow({ className, children, ...props }: PreviewCardPrimitive.Arrow.Props) {
  return (
    <PreviewCardPrimitive.Arrow
      data-slot="preview-card-arrow"
      className={mergeClassName(className, styles.arrow)}
      {...props}
    >
      {children ?? <ArrowSvg className={styles.arrowSvg} />}
    </PreviewCardPrimitive.Arrow>
  );
}

function PreviewCardViewport({ className, ...props }: PreviewCardPrimitive.Viewport.Props) {
  return (
    <PreviewCardPrimitive.Viewport
      data-slot="preview-card-viewport"
      className={mergeClassName(className, styles.viewport)}
      {...props}
    />
  );
}

function PreviewCardContent({
  className,
  sideOffset = DEFAULT_SIDE_OFFSET,
  side,
  align,
  alignOffset,
  arrowPadding,
  collisionAvoidance,
  collisionBoundary,
  collisionPadding,
  showArrow = false,
  children,
  ...props
}: PreviewCardContentProps) {
  return (
    <PreviewCardPortal>
      <PreviewCardPositioner
        side={side}
        sideOffset={sideOffset}
        align={align}
        alignOffset={alignOffset}
        arrowPadding={arrowPadding}
        collisionAvoidance={collisionAvoidance}
        collisionBoundary={collisionBoundary}
        collisionPadding={collisionPadding}
      >
        <PreviewCardPopup className={className} {...props}>
          {showArrow ? <PreviewCardArrow /> : null}
          <PreviewCardViewport>{children}</PreviewCardViewport>
        </PreviewCardPopup>
      </PreviewCardPositioner>
    </PreviewCardPortal>
  );
}

function ArrowSvg(props: ComponentProps<'svg'>) {
  return (
    <PopupArrowIcon
      fillClassName={styles.arrowFill}
      outerStrokeClassName={styles.arrowOuterStroke}
      innerStrokeClassName={styles.arrowInnerStroke}
      {...props}
    />
  );
}

export {
  PreviewCard,
  createPreviewCardHandle,
  PreviewCardTrigger,
  PreviewCardPortal,
  PreviewCardBackdrop,
  PreviewCardPositioner,
  PreviewCardPopup,
  PreviewCardArrow,
  PreviewCardViewport,
  PreviewCardContent,
};

@layer ui.components {
  .trigger {
    outline: 0;
    color: var(--preview-card-trigger-color, var(--color-primary));
    text-decoration-line: underline;
    text-decoration-thickness: var(--preview-card-trigger-decoration-thickness, 1px);
    text-decoration-color: var(
      --preview-card-trigger-decoration-color,
      color-mix(in oklab, var(--preview-card-trigger-color, var(--color-primary)), transparent 40%)
    );
    text-underline-offset: var(--preview-card-trigger-underline-offset, 2px);
    transition:
      color var(--preview-card-transition, var(--transition-default)),
      text-decoration-color var(--preview-card-transition, var(--transition-default));

    @media (hover: hover) {
      &:hover {
        text-decoration-color: var(
          --preview-card-trigger-decoration-color-hover,
          var(--preview-card-trigger-color, var(--color-primary))
        );
      }
    }

    &[data-popup-open] {
      text-decoration-color: var(
        --preview-card-trigger-decoration-color-open,
        var(--preview-card-trigger-color, var(--color-primary))
      );
    }

    &:focus-visible {
      border-radius: var(--preview-card-trigger-focus-radius, var(--radius-xs));
      outline: var(--preview-card-focus-ring-width, var(--border-width-sm)) solid
        var(--preview-card-focus-ring-color, var(--color-ring));
      outline-offset: var(--preview-card-trigger-focus-offset, 1px);
      text-decoration-line: none;
    }

    &[data-disabled],
    &[disabled] {
      pointer-events: none;
      opacity: var(--preview-card-disabled-opacity, var(--opacity-disabled));
    }
  }

  .backdrop {
    position: fixed;
    z-index: var(--z-backdrop);
    inset: 0;
    min-height: 100dvh;
    pointer-events: none;
    background-color: var(--preview-card-backdrop-bg, var(--backdrop-bg, var(--color-overlay)));
    backdrop-filter: var(--backdrop-filter, blur(var(--preview-card-backdrop-blur, 4px)));
    transition:
      opacity var(--preview-card-backdrop-transition, var(--transition-default)),
      backdrop-filter var(--preview-card-backdrop-transition, var(--transition-default));

    &[data-starting-style],
    &[data-ending-style] {
      opacity: 0;
      backdrop-filter: none;
    }
  }

  .positioner {
    z-index: var(--z-popup);
    width: var(--positioner-width);
    height: var(--positioner-height);
    max-width: var(--available-width);
    outline: 0;
  }

  .popup {
    box-sizing: border-box;
    width: var(--popup-width, var(--preview-card-width, auto));
    height: var(--popup-height, var(--preview-card-height, auto));
    min-width: min(var(--preview-card-min-width, 14rem), var(--available-width));
    max-width: min(var(--preview-card-max-width, 24rem), var(--available-width));
    max-height: min(var(--preview-card-max-height, 24rem), var(--available-height, 100dvh));
    overflow: visible;
    padding: var(--preview-card-padding-y, var(--spacing-2))
      var(--preview-card-padding-x, var(--spacing-2));
    border-radius: var(--preview-card-radius, var(--radius-lg));
    background-color: var(--preview-card-bg, var(--color-popover));
    color: var(--preview-card-color, var(--color-popover-foreground));
    outline: var(--preview-card-border-width, var(--border-width-sm)) solid
      var(--preview-card-border-color, var(--color-border));
    box-shadow: var(--preview-card-shadow, var(--shadow-lg));
    transform-origin: var(--transform-origin);
    transition:
      transform var(--preview-card-transition, var(--transition-default)),
      opacity var(--preview-card-transition, var(--transition-default));

    &[data-starting-style],
    &[data-ending-style] {
      opacity: 0;
      transform: scale(var(--preview-card-scale, var(--scale-popup)));
    }
  }

  .arrow {
    display: flex;
    color: var(--preview-card-bg, var(--color-popover));

    &[data-side='top'] {
      bottom: calc(var(--preview-card-arrow-size, 8px) * -1);
      rotate: 180deg;
    }

    &[data-side='bottom'] {
      top: calc(var(--preview-card-arrow-size, 8px) * -1);
    }

    &[data-side='left'] {
      right: calc(var(--preview-card-arrow-inline-offset, 13px) * -1);
      rotate: 90deg;
    }

    &[data-side='right'] {
      left: calc(var(--preview-card-arrow-inline-offset, 13px) * -1);
      rotate: -90deg;
    }
  }

  .arrowSvg {
    display: block;
    width: var(--preview-card-arrow-width, 1.25rem);
    height: var(--preview-card-arrow-height, 0.625rem);
    overflow: visible;
  }

  .arrowFill {
    fill: currentColor;
  }

  .arrowOuterStroke {
    fill: var(
      --preview-card-arrow-stroke-color,
      var(--preview-card-border-color, var(--color-border))
    );
  }

  .arrowInnerStroke {
    fill: var(--preview-card-bg, var(--color-popover));
  }

  .viewport {
    position: relative;
    overflow: clip;
    width: 100%;
    height: 100%;
  }
}
